mapper.update:
/* 마이페이지 수정 */
UPDATE TB_USER
SET
    USER_NM = #{userNm},
    EMAIL = #{email},
    PHONE = #{phone},
    ORG_ID = #{orgId},
    MODIFY_DT = NOW(),
    MDFR_ID = #{userId}
WHERE USER_ID = #{userId}

/* 마이페이지 비밀번호 변경 */
UPDATE TB_USER
SET
    PASSWD = #{passwd},
    PWD_CHG_DT = NOW(),
    LOGIN_FAIL_CNT = 0,
    MODIFY_DT = NOW(),
    MDFR_ID = #{userId}
WHERE USER_ID = #{userId}

mapper.select:
/* 마이페이지 비밀번호 변경 시 현재 비밀번호 확인용 */
SELECT PASSWD
FROM TB_USER
WHERE USER_ID = #{userId}
